  import sailpoint.tools.Util;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;


  String userName = account.getStringAttribute("User Name") ;

  Map returnMap = new HashMap();

  if(Util.isNotNullOrEmpty(userName)){

    String[] adDomainsForSearch = {"TNNAS"} ;
    String adApplicationType = "Active Directory - Direct" ;

    Filter linksApplicationTypeFilter = Filter.eq("links.application.type", adApplicationType) ; 
    Filter linksDisplayNameFilter = null ;

    Filter finalFilter = null ;

    for(String adDomainName: adDomainsForSearch){

      if(linksDisplayNameFilter==null){

        linksDisplayNameFilter = Filter.eq("links.displayName", adDomainName+"\\"+userName) ;

      } else {

        linksDisplayNameFilter = Filter.or(linksDisplayNameFilter, Filter.eq("links.displayName",adDomainName+"\\"+userName)) ; 
      }
    }

    finalFilter = Filter.and(linksApplicationTypeFilter,linksDisplayNameFilter) ;

    QueryOptions ops = new QueryOptions();
    ops.addFilter(finalFilter);

    List matchedIdentities = context.getObjects(Identity.class, ops);

    if (matchedIdentities != null && matchedIdentities.size() == 1) {

      String matchedIdentityCubeName = matchedIdentities.get(0).getName() ;

      returnMap.put("identityName", matchedIdentityCubeName); 

    }  
  }

  return returnMap ;
